class Solution:
    def summaryRanges(self, nums: List[int]) -> List[str]:
        res, i, n = [], 0, len(nums)
        while i < n:
            start = i
            while i + 1 < n and nums[i + 1] == nums[i] + 1:
                i += 1
            if start == i:
                res.append(str(nums[start]))
            else:
                res.append(f"{nums[start]}->{nums[i]}")
            i += 1
        return res

